-- Remove overloads antigos de create/update_cliente (sem p_potencial_cliente) que causavam ambiguidade no PostgREST.
DROP FUNCTION IF EXISTS public.create_cliente(p_user_id uuid, p_nome character varying, p_cliente_estrangeiro boolean, p_cnpj character varying, p_tipo crm.cliente_tipo, p_rua character varying, p_numero character varying, p_complemento character varying, p_bairro character varying, p_cidade character varying, p_estado character varying, p_cep character varying, p_codigo_ibge character varying, p_email character varying, p_telefone character varying, p_regime_fiscal character varying, p_grupo_economico_id uuid, p_observacoes text, p_segmento_ids uuid[], p_resp_int_nome character varying, p_resp_int_email character varying, p_resp_int_whatsapp character varying, p_resp_int_data_nascimento date, p_resp_fin_nome character varying, p_resp_fin_email character varying, p_resp_fin_whatsapp character varying, p_responsaveis_financeiros jsonb);
DROP FUNCTION IF EXISTS public.update_cliente(p_user_id uuid, p_cliente_id uuid, p_nome character varying, p_cliente_estrangeiro boolean, p_cnpj character varying, p_tipo crm.cliente_tipo, p_rua character varying, p_numero character varying, p_complemento character varying, p_bairro character varying, p_cidade character varying, p_estado character varying, p_cep character varying, p_codigo_ibge character varying, p_email character varying, p_telefone character varying, p_regime_fiscal character varying, p_grupo_economico_id uuid, p_observacoes text, p_segmento_ids uuid[], p_resp_int_nome character varying, p_resp_int_email character varying, p_resp_int_whatsapp character varying, p_resp_int_data_nascimento date, p_resp_fin_nome character varying, p_resp_fin_email character varying, p_resp_fin_whatsapp character varying, p_responsaveis_financeiros jsonb);
